var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그림자......?","JPN":"シャドウ……？","ENG":"Shadow?","TWN":"暗影？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"미, 미안하다. 잘 못 들었어. 방금 뭐라고 했지?","JPN":"す、すまない。よく聞こえなかった。今何と言った？","ENG":"S-sorry. I must have misheard you. What did you just say?","TWN":"抱、抱歉，我沒有聽清楚。妳剛才說什麼？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네게 악의는 없는 것 같지만, 그렇다고 사실이 바뀌지는 않아.","JPN":"あなたに敵意はないようだけど、それでも事実は変わらないわ。","ENG":"You don't seem to have any malicious ulterior motives... but that doesn't change the fact.","TWN":"儘管妳沒有惡意，但事實卻不會改變。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대답해! 방금 날 뭐라고 불렀는지!","JPN":"答えろ！　今、私を何と呼んだ！","ENG":"Answer me! What did you just call me?","TWN":"回答我！妳剛才說我是什麼！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자.","JPN":"シャドウ。","ENG":"A Shadow.","TWN":"暗影。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넌...... 그저 자신이 류드밀라라고 착각하는 그림자형 침식체일 뿐이라는 말이다.","JPN":"あなたは……自分のことをリュドミラだと思い込んでる、\\nシャドウ型侵食体でしかないのよ。","ENG":"You're... just a Shadow-type C.O. who thinks she's Lyudmila.","TWN":"妳只是……妳只是把自己當成盧德米拉的暗影型侵蝕體。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하, 하하......","JPN":"ハ、ハハ……","ENG":"Hah... hah hah...","TWN":"哈、哈哈……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"농담 할 줄 모르는 건 예전과 똑같군.","JPN":"冗談が下手なのは昔と変わらないな。","ENG":"You've always had a terrible sense of humor.","TWN":"妳還是和以前一樣，這麼不會開玩笑。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"웃자고 한 말이라면 정말 재미없었어.","JPN":"笑わせたつもりなら、これは苦笑いだぞ。","ENG":"Sorry, but that joke was in poor taste.","TWN":"如果妳是在開玩笑的話，這一點都不好笑。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"말이 되는 소릴 해, 이수연!","JPN":"バカも休み休み言え、カナミ！","ENG":"Do you even know what you're saying, Sooyeon?","TWN":"妳覺得這可能嗎，李秀妍！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"난 그날 이후로 수십 년 동안 혼자 계속 여기서 싸워 왔어!","JPN":"私はあの日以来、何十年にもわたって一人で戦ってきた！","ENG":"I've been fighting here for decades all by myself since that day!","TWN":"從那一天起，數十年以來，我一直留在這裡，一個人不斷地戰鬥！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 이제 와서 나타난 이유가, 겨우 그런 말을 하기 위해서였나?","JPN":"今更現れたと思えば、そんな世迷言を言うために来たというのか？","ENG":"And you show up after all those years and tell me this?","TWN":"而妳如今出現在我面前，就是為了對我說這些？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......바로 그게 문제야.","JPN":"……そこがこの話の肝よ。","ENG":"That's exactly the problem here.","TWN":"……這就是問題所在了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"인간은 이면세계에서 수십 년을 싸울 수 없어.","JPN":"人間は、裏世界で何十年も戦うことはできないわ。","ENG":"Humans can't fight for decades in the Counterside.","TWN":"人類是沒辦法在異界戰鬥數十年的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"何……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇지 않나? 정상적인 군대도 매일 격전에 치르면서 수십 년을 싸우면 보통은 미쳐 버릴 거야.","JPN":"だってそうでしょう？　正常に機能する軍隊でも\\n激戦の日々が数十年も続けば、普通は正気を保てないはずよ。","ENG":"Don't you get it? Even a well-trained army would go insane if they had to fight this hard every day for decades.","TWN":"難道不是嗎？就算是一個正常的軍隊，如果每天都在激戰，就這樣打了數十年，一定也會發瘋的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 넌 멀쩡하게 살아서, 하루하루를 지치지도 않고 싸워 왔지.","JPN":"でもあなたは正気を保ったまま、\\n疲弊することなく戦いの日々を生き抜いてきたわ。","ENG":"But you've managed to not only stay alive, but fight every day without tiring.","TWN":"而妳卻能活得好好的，每天不知疲倦地戰鬥下去。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};